svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var ns          = 'http://www.w3.org/2000/svg';
    var dataLayerEl = svgEl.querySelector('.data-layer');
    var dataItemEls = ctx.$$all('.data-item');

    var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
    var xs   = [126.9, 221.8, 316.7, 411.6, 506.4, 601.3, 696.2, 791.1];
    var colW = 36;
    var series = [
      { label:'Cyan',    cls:'series-1', vals:[38,42,46,50,55,60,66,72] },
      { label:'Violet',  cls:'series-2', vals:[32,35,38,41,45,50,56,62] },
      { label:'Emerald', cls:'series-3', vals:[18,20,21,23,25,27,31,35] },
      { label:'Amber',   cls:'series-4', vals:[11,12,13,14,15,17,19,22] },
      { label:'Slate',   cls:'series-5', vals:[10,11,12,13,14,16,17,19] },
    ];
    var totals = xs.map(function(_,qi){
      return series.reduce(function(s,sr){ return s+sr.vals[qi]; }, 0);
    });

    var hitLayer = svgEl.querySelector('#hit-layer');
    var tipLayer = svgEl.querySelector('#tip-layer');
    var allTips  = {};

    function el(tag, attrs) {
      var e = document.createElementNS(ns, tag);
      Object.keys(attrs).forEach(function(k){ e.setAttribute(k, attrs[k]); });
      return e;
    }

    xs.forEach(function(x, qi) {
      var PAD = 22, DOT_R = 5, DOT_X = 20, LBL_X = 38;
      var rowH = 42, hdrH = 38, divH = 12, totH = 46;
      var bh = hdrH + divH + series.length * rowH + divH + totH + PAD;
      var rx = 12;

      var tipG = el('g', {'class':'tip', id:'tip_'+qi});
      tipLayer.appendChild(tipG);
      allTips[qi] = tipG;

      var qLbl = el('text', {x:0, y:0, 'text-anchor':'middle',
        'dominant-baseline':'central', 'class':'tip-label'});
      qLbl.textContent = quarters[qi];
      tipG.appendChild(qLbl);

      var rowEls = [];
      series.forEach(function(s, si) {
        var rowY = hdrH + divH + si * rowH + rowH / 2;
        var dot  = el('circle', {cx:0, cy:rowY, r:DOT_R, 'class':s.cls});
        var sLbl = el('text', {x:LBL_X, y:rowY, 'dominant-baseline':'central', 'class':'tip-label'});
        sLbl.textContent = s.label;
        var sVal = el('text', {x:0, y:rowY, 'text-anchor':'end',
          'dominant-baseline':'central', 'class':'tip-value', 'font-size':'18'});
        sVal.textContent = '$' + s.vals[qi] + 'M';
        tipG.appendChild(dot); tipG.appendChild(sLbl); tipG.appendChild(sVal);
        rowEls.push({dot:dot, sLbl:sLbl, sVal:sVal});
      });

      var totY = hdrH + divH + series.length * rowH + divH + totH / 2;
      var totLbl = el('text', {x:LBL_X, y:totY, 'dominant-baseline':'central', 'class':'tip-label'});
      totLbl.textContent = 'Total';
      var totVal = el('text', {x:0, y:totY, 'text-anchor':'end',
        'dominant-baseline':'central', 'class':'tip-value'});
      totVal.textContent = '$' + totals[qi] + 'M';
      tipG.appendChild(totLbl); tipG.appendChild(totVal);

      var maxLblW = 0;
      rowEls.forEach(function(r) { maxLblW = Math.max(maxLblW, LBL_X + r.sLbl.getBBox().width + 8); });
      maxLblW = Math.max(maxLblW, LBL_X + totLbl.getBBox().width + 8);
      var maxValW = 0;
      rowEls.forEach(function(r) { maxValW = Math.max(maxValW, r.sVal.getBBox().width); });
      maxValW = Math.max(maxValW, totVal.getBBox().width);
      var hw = Math.max((maxLblW + maxValW) / 2 + PAD, 160);

      var bw = hw * 2;
      var barHW = 36;
      var TAIL = 14, tw = 10;
      var spaceR = 850 - (x + barHW);
      var spaceL = (x - barHW) - 68;
      var goRight = spaceR >= spaceL;
      var ancX, bL, bR;
      if (goRight) {
        ancX = x + barHW; bL = ancX + TAIL; bR = bL + bw;
      } else {
        ancX = x - barHW; bR = ancX - TAIL; bL = bR - bw;
      }
      var bCx = (bL + bR) / 2;

      /* vertical: center on chart area [100, 508] */
      var bT = 304 - bh / 2, bB = bT + bh;
      if (bT < 100) { bT = 100; bB = bT + bh; }
      if (bB > 508) { bB = 508; bT = bB - bh; }
      var ancY = (bT + bB) / 2;
      var tY = Math.max(bT + rx + tw, Math.min(bB - rx - tw, ancY));

      qLbl.setAttribute('x', String(bCx));
      qLbl.setAttribute('y', String(bT + hdrH / 2));
      rowEls.forEach(function(r) {
        r.dot.setAttribute('cx', String(bL + DOT_X));
        r.sLbl.setAttribute('x', String(bL + LBL_X));
        r.sVal.setAttribute('x', String(bR - 16));
        var rowY = bT + hdrH + divH + rowEls.indexOf(r) * rowH + rowH / 2;
        r.dot.setAttribute('cy', String(rowY));
        r.sLbl.setAttribute('y', String(rowY));
        r.sVal.setAttribute('y', String(rowY));
      });
      var absTotY = bT + hdrH + divH + series.length * rowH + divH + totH / 2;
      totLbl.setAttribute('x', String(bL + LBL_X));
      totLbl.setAttribute('y', String(absTotY));
      totVal.setAttribute('x', String(bR - 16));
      totVal.setAttribute('y', String(absTotY));

      var div1Y = bT + hdrH + divH / 2;
      var div2Y = bT + hdrH + divH + series.length * rowH + divH / 2;
      tipG.insertBefore(el('line', {x1:bL+14, y1:div1Y, x2:bR-14, y2:div1Y, 'class':'tip-div'}), qLbl.nextSibling);
      tipG.appendChild(el('line', {x1:bL+14, y1:div2Y, x2:bR-14, y2:div2Y, 'class':'tip-div'}));

      tipG.insertBefore(el('rect', {x:bL, y:bT, width:bw, height:bh, rx:rx, 'class':'tip-bg'}), tipG.firstChild);

      var borderPath, tailPath;
      if (goRight) {
        borderPath = 'M'+bL+','+(tY-tw)+
          ' L'+bL+','+(bT+rx)+' Q'+bL+','+bT+' '+(bL+rx)+','+bT+
          ' L'+(bR-rx)+','+bT+' Q'+bR+','+bT+' '+bR+','+(bT+rx)+
          ' L'+bR+','+(bB-rx)+' Q'+bR+','+bB+' '+(bR-rx)+','+bB+
          ' L'+(bL+rx)+','+bB+' Q'+bL+','+bB+' '+bL+','+(bB-rx)+
          ' L'+bL+','+(tY+tw);
        tailPath = 'M'+bL+','+(tY+tw)+' L'+ancX+','+ancY+' L'+bL+','+(tY-tw);
      } else {
        borderPath = 'M'+bR+','+(tY+tw)+
          ' L'+bR+','+(bB-rx)+' Q'+bR+','+bB+' '+(bR-rx)+','+bB+
          ' L'+(bL+rx)+','+bB+' Q'+bL+','+bB+' '+bL+','+(bB-rx)+
          ' L'+bL+','+(bT+rx)+' Q'+bL+','+bT+' '+(bL+rx)+','+bT+
          ' L'+(bR-rx)+','+bT+' Q'+bR+','+bT+' '+bR+','+(bT+rx)+
          ' L'+bR+','+(tY-tw);
        tailPath = 'M'+bR+','+(tY-tw)+' L'+ancX+','+ancY+' L'+bR+','+(tY+tw);
      }
      tipG.insertBefore(el('path', {d:borderPath, 'class':'tip-border'}), tipG.children[1]);
      tipG.insertBefore(el('path', {d:tailPath, 'class':'tip-tail'}), tipG.children[2]);

      var hit = el('rect', {x:x-colW, y:100, width:colW*2, height:408, fill:'transparent', cursor:'crosshair'});
      hitLayer.appendChild(hit);
      var ch = svgEl.querySelector('#ch'+qi);

      hit.addEventListener('mouseenter', function() {
        dataItemEls.forEach(function(c){ c.classList.remove('active'); });
        allTips[qi].style.opacity = '1';
        if (ch) ch.style.opacity = '1';
        dataLayerEl.classList.add('hovering');
        var itemEl = svgEl.querySelector('#data-item-'+qi);
        if (itemEl) itemEl.classList.add('active');
      });
      hit.addEventListener('mouseleave', function() {
        allTips[qi].style.opacity = '';
        if (ch) ch.style.opacity = '';
        dataLayerEl.classList.remove('hovering');
        var itemEl = svgEl.querySelector('#data-item-'+qi);
        if (itemEl) itemEl.classList.remove('active');
      });
    });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
